import React, { useEffect, useMemo, useState } from "react";

// Use same backend URL everywhere
const apiBase =
  process.env.REACT_APP_API_URL || "https://prasa-backend-1.onrender.com";

const AddExpense = ({ type, employee, onBack }) => {
  const isTravel = type === "travel";

  const [travelForm, setTravelForm] = useState({
    travel_date: "",
    purpose: "",
    amount: "",
    location_from: "",
    location_to: "",
    mode_of_travel: "",
    expense_type: "Transport",
  });

  const [ticketForm, setTicketForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
    status: "Pending",
  });

  const [expenses, setExpenses] = useState([]);
  const [filterMonth, setFilterMonth] = useState(""); // YYYY-MM
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState(null); // current editing row id

  // ---------- LOAD DATA ----------
  const endpoint = isTravel ? "travel-expenses" : "ticket-expenses";

  const loadExpenses = async () => {
    if (!employee || !employee.employee_id) return;
    try {
      setLoading(true);
      const res = await fetch(`${apiBase}/${endpoint}`);
      if (!res.ok) throw new Error("Server error");
      const data = await res.json();

      // Only show current employee
      const filtered = data.filter(
        (row) => row.employee_id === employee.employee_id
      );
      setExpenses(filtered);
      setMessage("");
    } catch (err) {
      console.error("Load expenses error:", err);
      setMessage("❌ Could not load expenses. Check server.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadExpenses();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [employee, type]);

  // ---------- FORM SUBMIT ----------
  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const url =
        editingId == null
          ? `${apiBase}/${endpoint}`
          : `${apiBase}/${endpoint}/${editingId}`;

      const method = editingId == null ? "POST" : "PUT";

      const body = isTravel
        ? {
            employee_id: employee.employee_id,
            ...travelForm,
            amount: parseFloat(travelForm.amount || 0),
          }
        : {
            employee_id: employee.employee_id,
            ...ticketForm,
            amount: parseFloat(ticketForm.amount || 0),
          };

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      const data = await res.json();
      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to save"));
      } else {
        setMessage(
          editingId == null
            ? "✅ Expense added successfully."
            : "✅ Expense updated successfully."
        );
        setEditingId(null);
        resetForm();
        loadExpenses();
      }
    } catch (err) {
      console.error("Submit error:", err);
      setMessage("❌ Server error while saving expense.");
    }
  };

  const resetForm = () => {
    setTravelForm({
      travel_date: "",
      purpose: "",
      amount: "",
      location_from: "",
      location_to: "",
      mode_of_travel: "",
      expense_type: "Transport",
    });
    setTicketForm({
      ticket_date: "",
      purpose: "",
      assigned_to: "",
      amount: "",
      status: "Pending",
    });
  };

  // ---------- EDIT ----------
  const startEdit = (exp) => {
    setEditingId(isTravel ? exp.travel_id : exp.ticket_id);
    if (isTravel) {
      setTravelForm({
        travel_date: exp.travel_date
          ? exp.travel_date.substring(0, 10)
          : "", // YYYY-MM-DD
        purpose: exp.purpose || "",
        amount: String(exp.amount || ""),
        location_from: exp.location_from || "",
        location_to: exp.location_to || "",
        mode_of_travel: exp.mode_of_travel || "",
        expense_type: exp.expense_type || "Transport",
      });
    } else {
      setTicketForm({
        ticket_date: exp.ticket_date
          ? exp.ticket_date.substring(0, 10)
          : "",
        purpose: exp.purpose || "",
        assigned_to: exp.assigned_to || "",
        amount: String(exp.amount || ""),
        status: exp.status || "Pending",
      });
    }
  };

  // ---------- DELETE ----------
  const deleteExpense = async (exp) => {
    const id = isTravel ? exp.travel_id : exp.ticket_id;
    if (!window.confirm("Are you sure you want to delete this expense?")) return;

    try {
      const res = await fetch(`${apiBase}/${endpoint}/${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to delete"));
      } else {
        setMessage("✅ Expense deleted.");
        loadExpenses();
      }
    } catch (err) {
      console.error("Delete error:", err);
      setMessage("❌ Server error while deleting.");
    }
  };

  // ---------- FILTER BY MONTH ----------
  const filteredExpenses = useMemo(() => {
    if (!filterMonth) return expenses;

    return expenses.filter((exp) => {
      const rawDate = isTravel ? exp.travel_date : exp.ticket_date;
      if (!rawDate) return false;
      const d = new Date(rawDate);
      if (isNaN(d.getTime())) return false;
      const ym = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(
        2,
        "0"
      )}`;
      return ym === filterMonth;
    });
  }, [expenses, filterMonth, isTravel]);

  // ---------- SUMMARY ----------
  const summary = useMemo(() => {
    let total = 0;
    filteredExpenses.forEach((exp) => {
      const val = parseFloat(exp.amount || 0);
      if (!isNaN(val)) total += val;
    });
    return {
      count: filteredExpenses.length,
      total,
    };
  }, [filteredExpenses]);

  // ---------- EXPORT CSV / EXCEL ----------
  const exportCSV = () => {
    if (!filteredExpenses.length) {
      alert("No data to export");
      return;
    }

    const header = isTravel
      ? [
          "Date",
          "Purpose",
          "Amount",
          "From",
          "To",
          "Mode",
          "Type",
          "Status",
        ]
      : ["Date", "Purpose", "Assigned To", "Amount", "Status"];

    const rows = filteredExpenses.map((exp) =>
      isTravel
        ? [
            exp.travel_date ? exp.travel_date.substring(0, 10) : "",
            exp.purpose || "",
            exp.amount || "",
            exp.location_from || "",
            exp.location_to || "",
            exp.mode_of_travel || "",
            exp.expense_type || "",
            exp.approval_status || "",
          ]
        : [
            exp.ticket_date ? exp.ticket_date.substring(0, 10) : "",
            exp.purpose || "",
            exp.assigned_to || "",
            exp.amount || "",
            exp.status || "",
          ]
    );

    const csv =
      [header, ...rows]
        .map((row) => row.map((v) => `"${String(v).replace(/"/g, '""')}"`).join(","))
        .join("\n") + "\n";

    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = isTravel
      ? "travel-expenses.csv"
      : "ticket-expenses.csv";
    a.click();
    URL.revokeObjectURL(url);
  };

  // ---------- EXPORT PDF (Print) ----------
  const exportPDF = () => {
    window.print(); // user can select "Save as PDF"
  };

  // ---------- APPROVAL BADGE ----------
  const renderStatusBadge = (status) => {
    if (!status) return "-";
    const upper = String(status).toUpperCase();
    const isApproved = upper === "APPROVED";
    const bg = isApproved ? "#e6f4ea" : "#fff4e5";
    const color = isApproved ? "#137333" : "#b06000";
    return (
      <span
        style={{
          padding: "2px 8px",
          borderRadius: 999,
          fontSize: 12,
          background: bg,
          color,
          fontWeight: 600,
        }}
      >
        {status}
      </span>
    );
  };

  // ---------- UI ----------
  const title = isTravel ? "Travel Expense" : "Ticket Expense";

  return (
    <div
      style={{
        fontFamily: "Segoe UI",
        background: "#f5f7fb",
        minHeight: "100vh",
        padding: 24,
      }}
    >
      <div
        style={{
          maxWidth: 1100,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
          padding: 24,
        }}
      >
        {/* Header */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "flex-start",
            gap: 12,
            marginBottom: 20,
          }}
        >
          <div>
            <button
              onClick={onBack}
              style={{
                border: "1px solid #d0d7e2",
                background: "#fff",
                borderRadius: 999,
                padding: "4px 10px",
                fontSize: 13,
                cursor: "pointer",
                marginBottom: 8,
              }}
            >
              ⬅ Back
            </button>
            <h2 style={{ margin: 0, color: "#1b3b5f" }}>{title}</h2>
            <p style={{ margin: "4px 0 0", color: "#607089" }}>
              {employee.name} • {employee.emp_code} • {employee.department}
            </p>
          </div>

          {/* Summary + filters */}
          <div style={{ textAlign: "right" }}>
            <div style={{ marginBottom: 8 }}>
              <label
                style={{
                  fontSize: 13,
                  color: "#607089",
                  marginRight: 6,
                }}
              >
                Filter by month:
              </label>
              <input
                type="month"
                value={filterMonth}
                onChange={(e) => setFilterMonth(e.target.value)}
                style={{
                  padding: "4px 8px",
                  borderRadius: 6,
                  border: "1px solid #c5cfdd",
                }}
              />
            </div>
            <div style={{ fontSize: 13, color: "#455a64" }}>
              <div>
                <strong>{summary.count}</strong> record
                {summary.count === 1 ? "" : "s"}
              </div>
              <div>
                Total:{" "}
                <strong>
                  ₹{summary.total.toLocaleString("en-IN", { maximumFractionDigits: 2 })}
                </strong>
              </div>
            </div>
          </div>
        </div>

        {/* Top row: Form + Actions */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "minmax(0, 1.2fr) minmax(0, 1fr)",
            gap: 20,
            alignItems: "flex-start",
            marginBottom: 20,
          }}
        >
          {/* Form card */}
          <div
            style={{
              background: "#f9fbff",
              borderRadius: 12,
              padding: 16,
              border: "1px solid #dde5f2",
            }}
          >
            <h3 style={{ marginTop: 0, color: "#1b3b5f", fontSize: 18 }}>
              {editingId ? "Edit Expense" : "Add New Expense"}
            </h3>

            <form onSubmit={handleSubmit}>
              {isTravel ? (
                <>
                  <label style={labelStyle}>Date</label>
                  <input
                    type="date"
                    required
                    value={travelForm.travel_date}
                    onChange={(e) =>
                      setTravelForm({
                        ...travelForm,
                        travel_date: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Purpose</label>
                  <input
                    type="text"
                    required
                    value={travelForm.purpose}
                    onChange={(e) =>
                      setTravelForm({
                        ...travelForm,
                        purpose: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Amount (₹)</label>
                  <input
                    type="number"
                    required
                    value={travelForm.amount}
                    onChange={(e) =>
                      setTravelForm({
                        ...travelForm,
                        amount: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <div style={{ display: "flex", gap: 8 }}>
                    <div style={{ flex: 1 }}>
                      <label style={labelStyle}>From</label>
                      <input
                        type="text"
                        value={travelForm.location_from}
                        onChange={(e) =>
                          setTravelForm({
                            ...travelForm,
                            location_from: e.target.value,
                          })
                        }
                        style={inputStyle}
                      />
                    </div>
                    <div style={{ flex: 1 }}>
                      <label style={labelStyle}>To</label>
                      <input
                        type="text"
                        value={travelForm.location_to}
                        onChange={(e) =>
                          setTravelForm({
                            ...travelForm,
                            location_to: e.target.value,
                          })
                        }
                        style={inputStyle}
                      />
                    </div>
                  </div>

                  <label style={labelStyle}>Mode of Travel</label>
                  <input
                    type="text"
                    placeholder="Car / Train / Flight..."
                    value={travelForm.mode_of_travel}
                    onChange={(e) =>
                      setTravelForm({
                        ...travelForm,
                        mode_of_travel: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Expense Type</label>
                  <input
                    type="text"
                    value={travelForm.expense_type}
                    onChange={(e) =>
                      setTravelForm({
                        ...travelForm,
                        expense_type: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />
                </>
              ) : (
                <>
                  <label style={labelStyle}>Date</label>
                  <input
                    type="date"
                    required
                    value={ticketForm.ticket_date}
                    onChange={(e) =>
                      setTicketForm({
                        ...ticketForm,
                        ticket_date: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Purpose</label>
                  <input
                    type="text"
                    required
                    value={ticketForm.purpose}
                    onChange={(e) =>
                      setTicketForm({
                        ...ticketForm,
                        purpose: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Assigned To</label>
                  <input
                    type="text"
                    value={ticketForm.assigned_to}
                    onChange={(e) =>
                      setTicketForm({
                        ...ticketForm,
                        assigned_to: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Amount (₹)</label>
                  <input
                    type="number"
                    required
                    value={ticketForm.amount}
                    onChange={(e) =>
                      setTicketForm({
                        ...ticketForm,
                        amount: e.target.value,
                      })
                    }
                    style={inputStyle}
                  />

                  <label style={labelStyle}>Status</label>
                  <select
                    value={ticketForm.status}
                    onChange={(e) =>
                      setTicketForm({
                        ...ticketForm,
                        status: e.target.value,
                      })
                    }
                    style={{ ...inputStyle, paddingRight: 30 }}
                  >
                    <option value="Pending">Pending</option>
                    <option value="Approved">Approved</option>
                    <option value="Rejected">Rejected</option>
                  </select>
                </>
              )}

              <div style={{ marginTop: 12, display: "flex", gap: 8 }}>
                <button
                  type="submit"
                  style={{
                    background: "#0f9d58",
                    color: "#fff",
                    border: "none",
                    borderRadius: 8,
                    padding: "8px 16px",
                    cursor: "pointer",
                    fontWeight: 600,
                  }}
                >
                  {editingId ? "Save Changes" : "Add Expense"}
                </button>
                {editingId && (
                  <button
                    type="button"
                    onClick={() => {
                      setEditingId(null);
                      resetForm();
                    }}
                    style={{
                      background: "#fff",
                      color: "#555",
                      border: "1px solid #ccd3e0",
                      borderRadius: 8,
                      padding: "8px 16px",
                      cursor: "pointer",
                    }}
                  >
                    Cancel Edit
                  </button>
                )}
              </div>
            </form>

            {message && (
              <div
                style={{
                  marginTop: 10,
                  fontSize: 13,
                  color: message.startsWith("✅") ? "#0f9d58" : "#c62828",
                }}
              >
                {message}
              </div>
            )}
          </div>

          {/* Export / info card */}
          <div
            style={{
              background: "#fdfdfd",
              borderRadius: 12,
              padding: 16,
              border: "1px dashed #d0d7e2",
            }}
          >
            <h4 style={{ marginTop: 0, color: "#1b3b5f" }}>Tools</h4>
            <p style={{ fontSize: 13, color: "#607089", marginBottom: 12 }}>
              Use these tools to export or share expense history.
            </p>
            <button
              onClick={exportCSV}
              style={{
                width: "100%",
                marginBottom: 8,
                padding: "8px 12px",
                borderRadius: 8,
                border: "1px solid #2e7d32",
                background: "#e8f5e9",
                color: "#1b5e20",
                cursor: "pointer",
                fontWeight: 600,
              }}
            >
              ⬇ Export to Excel (CSV)
            </button>
            <button
              onClick={exportPDF}
              style={{
                width: "100%",
                padding: "8px 12px",
                borderRadius: 8,
                border: "1px solid #c62828",
                background: "#ffebee",
                color: "#b71c1c",
                cursor: "pointer",
                fontWeight: 600,
              }}
            >
              📄 Export / Print PDF
            </button>
            <p
              style={{
                fontSize: 11,
                color: "#90a0b8",
                marginTop: 10,
              }}
            >
              Tip: When printing, choose <strong>"Save as PDF"</strong> in the
              print dialog to export a PDF report.
            </p>
          </div>
        </div>

        {/* History table */}
        <h3 style={{ color: "#1b3b5f", marginTop: 8 }}>History</h3>

        {loading ? (
          <p>Loading...</p>
        ) : filteredExpenses.length === 0 ? (
          <p style={{ color: "#90a0b8" }}>No expenses found for this filter.</p>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
                fontSize: 13,
              }}
            >
              <thead>
                <tr style={{ background: "#eef2fb" }}>
                  <th style={thStyle}>Date</th>
                  <th style={thStyle}>Purpose</th>
                  {isTravel ? (
                    <>
                      <th style={thStyle}>From</th>
                      <th style={thStyle}>To</th>
                      <th style={thStyle}>Mode</th>
                      <th style={thStyle}>Type</th>
                      <th style={thStyle}>Status</th>
                    </>
                  ) : (
                    <>
                      <th style={thStyle}>Assigned To</th>
                      <th style={thStyle}>Status</th>
                    </>
                  )}
                  <th style={thStyle}>Amount</th>
                  <th style={thStyle}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredExpenses.map((exp) => {
                  const id = isTravel ? exp.travel_id : exp.ticket_id;
                  return (
                    <tr key={id} style={{ borderBottom: "1px solid #edf0f7" }}>
                      <td style={tdStyle}>
                        {(isTravel ? exp.travel_date : exp.ticket_date || "")
                          .toString()
                          .substring(0, 10)}
                      </td>
                      <td style={tdStyle}>{exp.purpose}</td>

                      {isTravel ? (
                        <>
                          <td style={tdStyle}>{exp.location_from || "-"}</td>
                          <td style={tdStyle}>{exp.location_to || "-"}</td>
                          <td style={tdStyle}>{exp.mode_of_travel || "-"}</td>
                          <td style={tdStyle}>{exp.expense_type || "-"}</td>
                          <td style={tdStyle}>
                            {renderStatusBadge(exp.approval_status || "Pending")}
                          </td>
                        </>
                      ) : (
                        <>
                          <td style={tdStyle}>{exp.assigned_to || "-"}</td>
                          <td style={tdStyle}>
                            {renderStatusBadge(exp.status || "Pending")}
                          </td>
                        </>
                      )}

                      <td style={tdStyle}>₹{exp.amount}</td>
                      <td style={{ ...tdStyle, whiteSpace: "nowrap" }}>
                        <button
                          onClick={() => startEdit(exp)}
                          style={actionButtonStyle("#1565c0", "#e3f2fd")}
                        >
                          Edit
                        </button>
                        <button
                          onClick={() => deleteExpense(exp)}
                          style={actionButtonStyle("#c62828", "#ffebee")}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

// ---------- Small style helpers ----------
const labelStyle = {
  display: "block",
  fontSize: 13,
  color: "#555",
  marginBottom: 4,
  marginTop: 8,
};

const inputStyle = {
  width: "100%",
  padding: "7px 9px",
  borderRadius: 8,
  border: "1px solid #ccd3e0",
  fontSize: 13,
  outline: "none",
};

const thStyle = {
  textAlign: "left",
  padding: "8px 10px",
  borderBottom: "1px solid #d9e0f0",
  fontWeight: 600,
  color: "#455a64",
};

const tdStyle = {
  padding: "7px 10px",
  fontSize: 13,
  color: "#37474f",
};

const actionButtonStyle = (color, bg) => ({
  border: "none",
  borderRadius: 999,
  padding: "4px 10px",
  fontSize: 12,
  cursor: "pointer",
  marginRight: 6,
  background: bg,
  color,
  fontWeight: 600,
});

export default AddExpense;
